module top_module(
    input [3:0] obf_inputs,
    input [1:0] select,
    output reg out
);always @(*) begin
    case (select)
        2'b00: out = obf_inputs[0];
        2'b01: out = obf_inputs[1];
        2'b10: out = obf_inputs[2];
        2'b11: out = obf_inputs[3];
    endcase
end

endmodule
